import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/extension-view.BUCve89_.js";const s=JSON.parse(`{"title":"VS Code einrichten","description":"Ein Schritt-für-Schritt-Leitfaden, wie man Visual Studio Code für die Erstellung von Mods mit Fabric einrichtet.","frontmatter":{"title":"VS Code einrichten","description":"Ein Schritt-für-Schritt-Leitfaden, wie man Visual Studio Code für die Erstellung von Mods mit Fabric einrichtet.","authors":["dicedpixels"],"prev":{"text":"Deine Entwicklungsumgebung einrichten","link":"../setting-up"},"next":{"text":"Ein Projekt in VS Code öffnen","link":"./opening-a-project"},"resources":{"https://code.visualstudio.com/":"Visual Studio Code herunterladen","https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack":"Extension Pack for Java - VS Marketplace"},"files":[]},"headers":[],"relativePath":"de_de/develop/getting-started/vscode/setting-up.md","filePath":"translated/de_de/develop/getting-started/vscode/setting-up.md","lastUpdated":1774711188000}`);var c={name:`de_de/develop/getting-started/vscode/setting-up.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">VS Code einrichten <a class="header-anchor" href="#h1" aria-label="Permalink to “VS Code einrichten”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Es ist zwar möglich, Mods mit Visual Studio Code zu entwickeln, wir raten jedoch davon ab. Erwäge die Verwendung vo <a href="./../intellij-idea/setting-up">IntelliJ IDEA</a>, das über spezielle Java-Tools, erweiterte Funktionen und nützliche, von der Community entwickelte Plugins wie <strong>Minecraft Development</strong> verfügt.</p></div><div class="info custom-block"><p class="custom-block-title">VORAUSSETZUNGEN</p><p>Stelle sicher, dass du zuerst <a href="./../setting-up#install-jdk-21">ein JDK installiert hast</a>.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>Du kannst Visual Studio Code von <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">code.visualstudio.com</a> oder über deinen bevorzugten Paketmanager herunterladen.</p><p><img src="/assets/develop/getting-started/vscode/download.png" alt="Visual Studio Code Download Seite" loading="lazy"></p><h2 id="prerequisites" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Voraussetzungen”">​</a></h2><p>Visual Studio Code bietet standardmäßig keine Unterstützung für die Programmiersprache Java. Microsoft bietet jedoch ein praktisches Erweiterungspaket an, das alle erforderlichen Erweiterungen enthält, um die Java-Sprachunterstützung zu aktivieren.</p><p>Du kannst dieses Erweiterungspaket über den <a href="https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack" target="_blank" rel="noreferrer">Visual Studio Marketplace</a> installieren.</p><p><img src="/assets/develop/getting-started/vscode/extension.png" alt="Erweiterungspaket für Java" loading="lazy"></p><p>Oder innerhalb von Visual Studio Code selbst über die Erweiterungsansicht.</p><p><img src="/assets/develop/getting-started/vscode/extension-view.png" alt="Erweiterungspaket für Java in der Erweiterungsansicht" loading="lazy"></p><p>Die Erweiterung <strong>Language Support for Java</strong> zeigt dir einen Startbildschirm zur Einrichtung eines JDK an. Du kannst dies machen, falls du es noch nicht gemacht hast.</p>`,13)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};